import{_ as e,o as i,c as t,a0 as l}from"./chunks/framework.DE0haUFQ.js";const p=JSON.parse('{"title":"528 Demo 方向讨论 — DataHub + WrenAI 语义层建设方案","description":"与 Kimi 的深入讨论，关于 AI 辅助语义层建设的可行方案、DataHub 能力分析、开源工具全景调研","frontmatter":{"type":"Source","title":"528 Demo 方向讨论 — DataHub + WrenAI 语义层建设方案","description":"与 Kimi 的深入讨论，关于 AI 辅助语义层建设的可行方案、DataHub 能力分析、开源工具全景调研","source_url":"n/a","source_title":"528_demo方向讨论","source_author":"Eason + Kimi","source_platform":"内部讨论","ingest_date":"2026-07-12T00:00:00.000Z","access_date":"2026-07-12T00:00:00.000Z","tags":["AI","数据治理","语义层","DataHub","WrenAI","工作"],"status":"compiled","review_count":0,"last_review":"2026-07-12T00:00:00.000Z","next_review":"2026-07-13T00:00:00.000Z"},"headers":[],"relativePath":"wiki/sources/2026-07-12-528-demo-discussion.md","filePath":"wiki/sources/2026-07-12-528-demo-discussion.md"}'),s={name:"wiki/sources/2026-07-12-528-demo-discussion.md"};function n(o,a,r,u,h,c){return i(),t("div",null,[...a[0]||(a[0]=[l(`<h1 id="_528-demo-方向讨论" tabindex="-1">528 Demo 方向讨论 <a class="header-anchor" href="#_528-demo-方向讨论" aria-label="Permalink to &quot;528 Demo 方向讨论&quot;">​</a></h1><h2 id="核心发现" tabindex="-1">核心发现 <a class="header-anchor" href="#核心发现" aria-label="Permalink to &quot;核心发现&quot;">​</a></h2><p><strong>市面上几乎没有&quot;语义层建设平台&quot;这个品类的开源产品</strong>。所有工具都是语义层的消费者，不是生产者。</p><h3 id="开源语义层工具全景" tabindex="-1">开源语义层工具全景 <a class="header-anchor" href="#开源语义层工具全景" aria-label="Permalink to &quot;开源语义层工具全景&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  WrenAI / Cube / MetricFlow / Vanna / Malloy / Superset      │</span></span>
<span class="line"><span>│                     ↓ 语义层的&quot;消费者&quot;                        │</span></span>
<span class="line"><span>│              （用户问数 → 查语义模型 → 生成SQL）              │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                   缺少的：语义层&quot;生产者&quot;                       │</span></span>
<span class="line"><span>│    （AI识别语义 → 置信度评分 → 人工审核 → 发布语义资产）       │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="datahub-能力分析" tabindex="-1">DataHub 能力分析 <a class="header-anchor" href="#datahub-能力分析" aria-label="Permalink to &quot;DataHub 能力分析&quot;">​</a></h2><h3 id="能做的-2025年底新增-ai-能力" tabindex="-1">能做的（2025年底新增 AI 能力） <a class="header-anchor" href="#能做的-2025年底新增-ai-能力" aria-label="Permalink to &quot;能做的（2025年底新增 AI 能力）&quot;">​</a></h3><ol><li>✅ AI 自动生成字段描述（表级 + 列级）</li><li>✅ AI 自动分类/打标签（敏感数据检测、词汇表术语提议）</li><li>✅ AI 数据质量规则提议（Freshness/Volume/Drift）</li><li>✅ Human-in-the-Loop 审核工作流（接受/编辑/拒绝）</li><li>✅ 血缘关系图可视化</li><li>✅ 词汇表管理（Glossary）</li></ol><h3 id="不能做的" tabindex="-1">不能做的 <a class="header-anchor" href="#不能做的" aria-label="Permalink to &quot;不能做的&quot;">​</a></h3><ol><li>❌ 同义词/黑话自动发现</li><li>❌ 多层语义抽象（L1-L5）</li><li>❌ NL2SQL/ChatBI（需要配合 WrenAI 等工具）</li><li>❌ 置信度评分机制</li></ol><h2 id="demo-策略建议" tabindex="-1">Demo 策略建议 <a class="header-anchor" href="#demo-策略建议" aria-label="Permalink to &quot;Demo 策略建议&quot;">​</a></h2><p><strong>三层组合拳</strong>：</p><h3 id="第一层-html汇报材料-重点" tabindex="-1">第一层：HTML汇报材料（重点） <a class="header-anchor" href="#第一层-html汇报材料-重点" aria-label="Permalink to &quot;第一层：HTML汇报材料（重点）&quot;">​</a></h3><ul><li>用 CSS 动画模拟语义层建设全过程</li><li>数据资产扫描 → AI自动打标签 → 置信度评分 → 人工审核面板 → 发布语义资产</li></ul><h3 id="第二层-wrenai-已有" tabindex="-1">第二层：WrenAI（已有） <a class="header-anchor" href="#第二层-wrenai-已有" aria-label="Permalink to &quot;第二层：WrenAI（已有）&quot;">​</a></h3><ul><li>展示&quot;有了语义层之后的效果&quot;</li><li>只放 DWS+ADS（10张表）</li></ul><h3 id="第三层-ppt提及方向-长期" tabindex="-1">第三层：PPT提及方向（长期） <a class="header-anchor" href="#第三层-ppt提及方向-长期" aria-label="Permalink to &quot;第三层：PPT提及方向（长期）&quot;">​</a></h3><ul><li>DataHub 作为元数据底座</li><li>dbt MetricFlow 作为语义引擎</li><li>自研 Agent 层作为 AI 辅助建设（差异化）</li></ul><h2 id="关键结论" tabindex="-1">关键结论 <a class="header-anchor" href="#关键结论" aria-label="Permalink to &quot;关键结论&quot;">​</a></h2><blockquote><p>&quot;DataHub 做元数据治理很强，但缺乏同义词发现/多层语义抽象/置信度评分——这是我们要补的。&quot;</p></blockquote><h2 id="关联" tabindex="-1">关联 <a class="header-anchor" href="#关联" aria-label="Permalink to &quot;关联&quot;">​</a></h2><ul><li><a href="/eason-pkms/projects/KimiAgentAIDataGovernance.html">Kimi_Agent_AI原生数据治理</a></li><li><a href="/eason-pkms/entities/DataHub.html">DataHub</a></li><li><a href="/eason-pkms/entities/WrenAI.html">WrenAI</a></li></ul><h1 id="citations" tabindex="-1">Citations <a class="header-anchor" href="#citations" aria-label="Permalink to &quot;Citations&quot;">​</a></h1><ul><li>来源: 第二大脑 / 0-Inbox/528_demo方向讨论.md</li><li>时间: 2026-05-28</li></ul>`,24)])])}const m=e(s,[["render",n]]);export{p as __pageData,m as default};
